class Solution(object):
    def maxPossibleScore(self, start, d):
        start.sort()
        n = len(start)

        def feasible(x):
            # Can we pick one number from each [start[i], start[i]+d] such that
            # consecutive chosen values differ by >= x?
            prev = start[0]  # pick smallest possible from first interval
            for i in range(1, n):
                nxt = prev + x
                if nxt > start[i] + d:
                    return False
                prev = max(nxt, start[i])  # earliest we can pick in interval i
            return True

        lo, hi = 0, (start[-1] + d - start[0])
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans
